// Normalize job data from different sources and deduplicate
const items = $input.all();
const jobMap = new Map();

for (const item of items) {
  const data = item.json;
  let normalized = {};

  if (data.jobtitle) {
    // Indeed format
    normalized = {
      job_id: 'indeed_' + data.jobkey,
      title: data.jobtitle,
      company: data.company,
      location: data.formattedLocation || data.city,
      description: data.snippet,
      url: data.url,
      posted_date: data.date,
      source: 'indeed',
      salary: null
    };

  } else if (data.results && Array.isArray(data.results)) {
    // Adzuna format - process each job in results array
    for (const result of data.results) {
      if (!result.title) continue;
      const adzunaJob = {
        job_id: 'adzuna_' + (result.id || Date.now()),
        title: result.title,
        company: result.company ? result.company.display_name : 'Unknown',
        location: result.location ? result.location.display_name : 'India',
        description: result.description || result.title,
        url: result.redirect_url || '',
        posted_date: result.created || new Date().toISOString(),
        source: 'adzuna',
        salary: result.salary_max ? (Math.round((result.salary_min||0)/100000) + '-' + Math.round(result.salary_max/100000) + ' LPA') : null
      };
      const adzunaKey = adzunaJob.title.toLowerCase() + '_' + adzunaJob.company.toLowerCase();
      if (!jobMap.has(adzunaKey)) { jobMap.set(adzunaKey, adzunaJob); }
    }
    continue;

  } else if (data.position) {
    // RemoteOK format
    normalized = {
      job_id: 'remoteok_' + data.id,
      title: data.position,
      company: data.company,
      location: data.location || 'Remote',
      description: data.description,
      url: data.url,
      posted_date: data.date,
      source: 'remoteok',
      salary: data.salary_max ? (data.salary_min + '-' + data.salary_max) : null
    };

  } else if (data.title && data['content:encoded']) {
    // RSS format (WeWorkRemotely, LinkedIn)
    normalized = {
      job_id: 'rss_' + (data.guid || data.link),
      title: data.title,
      company: data.company || 'Unknown',
      location: data.location || 'Remote',
      description: data['content:encoded'] || data.description,
      url: data.link,
      posted_date: data.pubDate,
      source: data.link.includes('linkedin') ? 'linkedin' : 'wwr',
      salary: null
    };

  } else {
    continue;
  }

  const key = normalized.title.toLowerCase() + '_' + normalized.company.toLowerCase();
  if (!jobMap.has(key)) {
    jobMap.set(key, normalized);
  }
}

const uniqueJobs = Array.from(jobMap.values()).map(job => ({ json: job }));
return uniqueJobs;

